ac:structured-macro.ac:plain-text-body:
@startuml skinparam componentStyle rectangle
package "Main Thread (every 15 min)" { [ResearchManager] as RM [Phase1: Maya + News + Macro] as P1 [Phase2: 7 Sector Agents\n(ThreadPoolExecutor)] as P2 [Phase3: Manager LLM\n(CIO Arbitration)] as P3 [TelegramReporter\n(alerts + reports)] as TR [Daily FinSnap Cache\nrefresh_financial_snapshot_cache()] as FS }
package "Bot Thread (daemon, long-poll)" { [BotServer] as BS [QAPipeline] as QA [LLMAnalyst\nplan_intent + chat_answer] as LA }
database "state (RLock)" { [israel_researcher_state.json] as STATE [financial_snapshot_cache] as FSC [stock_memory] as MEM [weekly_signals] as WS }
[Telegram API] as TG [Yahoo Finance / Maya / Google News] as EXT
RM --> P1 P1 --> P2 P2 --> P3 P3 --> TR RM --> FS FS --> FSC P1 --> STATE P2 --> STATE P3 --> TR TR --> TG
BS --> QA QA --> LA LA --> EXT : live tools\n(get_stock_data, search_news) LA --> FSC : screen_stocks QA --> TG : reply BS <-- TG : getUpdates
RM ..> STATE : RLock read/write BS ..> STATE : RLock deepcopy @enduml

@startuml
start

:Filter pre-fetched cross-sector signals\nfor this sector's tickers;

:MarketAnomalyDetector scan\n(volume_spike, price_move, breakout,\nma_crossover, oversold_bounce,\nlow_reversal, momentum, rel_strength);

:Sector-specific macro signals\n(peer ETF moves, shekel, oil/rates);

:ConvergenceEngine.group_by_ticker()\nPreliminary scoring;

if (any ticker with final_score > 0?) then (yes)
  :Web news enrichment for top-5\n(Google News RSS → LLM extract_web_news_signals);
  :Re-run ConvergenceEngine\nwith enriched signals;
  :DeepStockAnalyzer on top-8\n(RSI, MAs, P/E, P/B, margins,\nrevenue growth, market cap);
  :Build memory context strings\n(analyst notes, sentiment, risk flag);
  :Sector LLM score_sector()\nreturns ranked portfolio;
  :Update stock_memory with\nLLM insights (sentiment, risk, watch_for);
else (no signals)
  :Return empty portfolio;
endif

stop
@enduml

def _tool_financials(ticker: str | None, _state: dict, _top_n: int = 5) -> str:
    """Fetches annual + quarterly income statement + key balance sheet for one stock."""
    import math, yfinance as yf
    if not ticker:
        return "Please specify a stock ticker."
    ticker_yf = ticker if ticker.endswith(".TA") else ticker + ".TA"
    tk = yf.Ticker(ticker_yf)
    parts = [
        _fmt_financial(tk.financials, "Annual Income Statement (last 4 years)"),
        _fmt_financial(tk.quarterly_financials, "Quarterly Income Statement (last 4 quarters)"),
    ]
    # Key balance sheet items
    bs = tk.balance_sheet
    if bs is not None and not bs.empty:
        bs_lines = ["Balance Sheet (latest):"]
        for item in ["Total Assets","Total Debt","Cash And Cash Equivalents",
                     "Stockholders Equity","Total Liabilities Net Minority Interest"]:
            if item in bs.index:
                v = bs.loc[item, bs.columns[0]]
                bs_lines.append(f"  {item}: ₪{v/1e9:.2f}B" if abs(v) >= 1e9 else f"  {item}: ₪{v/1e6:.1f}M")
        parts.append("\n".join(bs_lines))
    return "\n\n".join(p for p in parts if p)

def _tool_screen_stocks(_ticker, state: dict, _top_n: int = 20) -> str:
    """Screens all major TASE stocks by financial metrics from daily cache."""
    cache = state.get("financial_snapshot_cache", {})
    if not cache:
        return "Financial snapshot cache not yet populated (runs once daily). Try again shortly."
    rows = sorted(
        [{"ticker": t.replace(".TA",""), **snap} for t, snap in cache.items() if snap],
        key=lambda r: r.get("mktCap") or 0, reverse=True
    )[:_top_n]
    lines = [f"{'Ticker':<10} {'Price':>8} {'MktCap':>10} {'P/E':>7} {'P/B':>6} {'Div%':>6} {'RevGr%':>8}"]
    lines.append("-" * 65)
    for r in rows:
        mc = r.get("mktCap")
        mc_str = f"₪{mc/1e9:.1f}B" if mc and mc >= 1e9 else (f"₪{mc/1e6:.0f}M" if mc else "N/A")
        price_str = f"₪{r['price']:.2f}" if r.get("price") else "N/A"
        def f(v): return f"{v:.1f}" if v is not None else "N/A"
        lines.append(f"{r['ticker']:<10} {price_str:>8} {mc_str:>10} {f(r.get('pe_trailing')):>7} {f(r.get('price_to_book')):>6} {f(r.get('dividend_yield')):>6} {f(r.get('revenue_growth_pct')):>8}")
    return "\n".join(lines)
